INSERT INTO settings (setting_key, setting_value, description) VALUES
('purchase_policy', '<h2>1. Hướng dẫn đặt hàng</h2><p>Quý khách có thể lựa chọn các sản phẩm trên website và thêm vào giỏ hàng. Tại trang thanh toán, quý khách vui lòng điền đầy đủ thông tin giao hàng để chúng tôi có thể phục vụ tốt nhất.</p><h2>2. Hình thức thanh toán</h2><ul><li><strong>Thanh toán chuyển khoản:</strong> Khách hàng chuyển khoản theo thông tin tài khoản hiển thị sau khi đặt hàng thành công.</li><li><strong>Thanh toán khi nhận hàng (COD):</strong> Khách hàng thanh toán bằng tiền mặt cho nhân viên giao hàng sau khi đã kiểm tra sản phẩm.</li></ul><h2>3. Thay đổi & Hủy đơn hàng</h2><p>Nếu muốn thay đổi sản phẩm hoặc hủy đơn hàng, quý khách vui lòng liên hệ ngay với Hotline của chúng tôi. Chúng tôi chỉ hỗ trợ hủy đơn trước khi sản phẩm được gửi đi cho đơn vị vận chuyển.</p><h2>4. Điều kiện áp dụng đổi trả</h2><p>Đặc thù là sản phẩm tự nhiên và có vòng đời ngắn, chúng tôi chỉ hỗ trợ xử lý đổi trả trong các trường hợp sau:</p><ul><li>Cây/hoa bị dập nát, gãy cành, héo úa nghiêm trọng do lỗi của quá trình vận chuyển.</li><li>Thiết kế thực tế khác biệt quá 30% so với hình ảnh mẫu hoặc sai tone màu chủ đạo đã chốt.</li><li>Sản phẩm được giao không đúng với đơn đặt hàng.</li></ul><h2>5. Thời gian khiếu nại</h2><p>Quý khách vui lòng cung cấp video/hình ảnh tình trạng sản phẩm và gửi về Hotline/Zalo ngay trong vòng <strong>2 giờ</strong> kể từ thời điểm nhận hàng. Quá thời gian này, chúng tôi xin phép từ chối giải quyết khiếu nại.</p><h2>6. Phương thức giải quyết</h2><p>Nếu lỗi thuộc về hệ thống, Green Elegance sẽ thu hồi sản phẩm cũ và giao sản phẩm mới thay thế trong thời gian sớm nhất, hoặc hoàn tiền 100% qua tài khoản ngân hàng của quý khách.</p>', 'Nội dung Chính sách mua hàng và đổi trả')
ON CONFLICT (setting_key) DO UPDATE SET
setting_value = EXCLUDED.setting_value,
updated_at = CURRENT_TIMESTAMP;
